+        let orders = pattern("tenant.orders.>");
+
+        let mut steward = CrdtPropagationReplica::<InterestSummary>::new(replica_a.clone());
+        let mut peer = CrdtPropagationReplica::<InterestSummary>::new(replica_b);
+
+        let envelope = steward
